  // ── Cobertura obligatoria: código "1" siempre seleccionada ───────────
  if (r.frm_cobertura_codigo === '1') {
    r.frm_cobertura_seleccionada = true;
  }

  const lastBase = toNum(r._last_base);
  const baseChanged = base !== lastBase;

  // ── Par 1: vigencia_pct <-> vigencia_valor ────────────────────────────
  const pctVig = toNum(r.frm_cobertura_limite_aseg_vigencia_pct);
  const valVig = toNum(r.frm_cobertura_limite_aseg_vigencia_valor);

  const lastPctVig = toNum(r._last_vigencia_pct);
  const lastValVig = toNum(r._last_vigencia_val);

  if (baseChanged) {
    // Base cambió: recalcular valor usando el % actual
    r.frm_cobertura_limite_aseg_vigencia_valor = round2((base * pctVig) / 100);
  } else if (pctVig !== lastPctVig) {
    r.frm_cobertura_limite_aseg_vigencia_valor = round2((base * pctVig) / 100);
  } else if (valVig !== lastValVig) {
    r.frm_cobertura_limite_aseg_vigencia_pct = round2((valVig / base) * 100);
  }

  r._last_vigencia_pct = toNum(r.frm_cobertura_limite_aseg_vigencia_pct);
  r._last_vigencia_val = toNum(r.frm_cobertura_limite_aseg_vigencia_valor);

  // ── Par 2: limiteAseg_porcentaje <-> cobertura_moneda ─────────────────
  const pctLim = toNum(r.frm_cobertura_limiteAseg_porcentaje);
  const valLim = toNum(r.frm_cobertura_moneda);

  const lastPctLim = toNum(r._last_limite_pct);
  const lastValLim = toNum(r._last_limite_val);

  if (baseChanged) {
    // Base cambió: recalcular valor usando el % actual
    r.frm_cobertura_moneda = round2((base * pctLim) / 100);
  } else if (pctLim !== lastPctLim) {
    r.frm_cobertura_moneda = round2((base * pctLim) / 100);
  } else if (valLim !== lastValLim) {
    r.frm_cobertura_limiteAseg_porcentaje = round2((valLim / base) * 100);
  }

  r._last_limite_pct = toNum(r.frm_cobertura_limiteAseg_porcentaje);
  r._last_limite_val = toNum(r.frm_cobertura_moneda);

  // ── Snapshot de la base ───────────────────────────────────────────────
  r._last_base = base;
});

return grd;

function formatearPuntos(valor) {
  return Number(valor).toLocaleString('de-DE', { maximumFractionDigits: 0 });
}

const grd = Array.isArray(this.grd_coberturas_seleccionadas)
