  } else {
    r.frm_cobertura_limite_aseg_vigencia_control = "";
  }

  const eventoValor = Number(r.frm_cobertura_moneda) || 0;

  if (eventoValor > base) {
    r.frm_cobertura_limite_aseg_evento_control = "EVENTO_SUPERADO";
  } else {
    r.frm_cobertura_limite_aseg_evento_control = "";
  }

  // 3er control
  if (eventoValor > vigenciaValor) {
    r.frm_cobertura_limite_aseg_evento_control_valor = "MONTO_SUPERADO";
  } else {
    r.frm_cobertura_limite_aseg_evento_control_valor = "";
  }

  // 4to Control
  r.frm_cobertura_limiteAseg_porcentaje_control = "";

  const pctLimite   = Number(r.frm_cobertura_limiteAseg_porcentaje) || 0;
  const pctPermitido = Number(r.frm_cobertura_limite_aseg_vigencia_pct) || 0;

  if (pctLimite > pctPermitido) {
    r.frm_cobertura_limiteAseg_porcentaje_control = "PORCENTAJE MAYOR AL PERMITIDO";
  } else {
    r.frm_cobertura_limiteAseg_porcentaje_control = "";
  }

  // 5to Control
  const frm_cobertura_deducible = Number(r.frm_cobertura_deducible) || 0;
  const valor_maximo_deducible_minimo_control = (eventoValor * frm_cobertura_deducible) / 100;
  r.frm_valor_maximo_deducible_minimo_control = formatearPuntos(valor_maximo_deducible_minimo_control);

  // 6to Control
  r.frm_control_maximo_deducible_minimo_coberturas = "";
  const frm_cobertura_deducible_minimo_valor      = Number(r.frm_cobertura_deducible_minimo_valor) || 0;
  const frm_cobertura_calculoDeducibleOpcion       = r.frm_cobertura_calculoDeducibleOpcion;

  if (frm_cobertura_calculoDeducibleOpcion == "VALOR") {
    if (frm_cobertura_deducible_minimo_valor > valor_maximo_deducible_minimo_control) {
      r.frm_control_maximo_deducible_minimo_coberturas = "VALOR_SUPERADO";
    }
  } else {
    r.frm_control_maximo_deducible_minimo_coberturas = "";
  }

  // 7mo Control
  /*
  const frm_cobertura_deducible_minimo = Number(r.frm_cobertura_deducible_minimo) || 0;
  if (frm_cobertura_calculoDeducibleOpcion == "SMMLV") {
    if (frm_cobertura_deducible_minimo > 2000) {
      r.frm_cobertura_deducible_minimo_control_excede_limite = "SUPERADO";
    } else {
      r.frm_cobertura_deducible_minimo_control_excede_limite = "";
    }
  } else {
    r.frm_cobertura_deducible_minimo_control_excede_limite = "";
  }

  */
  //7mo control
  // 7mo Control
  const deducibleMinimoRaw = r.frm_cobertura_deducible_minimo;
  const frm_cobertura_deducible_minimo = Number(deducibleMinimoRaw);

  if (frm_cobertura_calculoDeducibleOpcion == "SMMLV") {
    if (
      String(deducibleMinimoRaw ?? "").trim() === "" ||
      !Number.isFinite(frm_cobertura_deducible_minimo) ||
      frm_cobertura_deducible_minimo < 1 ||
      frm_cobertura_deducible_minimo > 2000
    ) {
      r.frm_cobertura_deducible_minimo_control_excede_limite = "SUPERADO";
    } else {
      r.frm_cobertura_deducible_minimo_control_excede_limite = "";
    }
  } else {
    r.frm_cobertura_deducible_minimo_control_excede_limite = "";
  }

  // 8vo control
  const frm_cobertura_limite_aseg_vigencia_tipo = r.frm_cobertura_limite_aseg_vigencia_tipo;
  if (frm_cobertura_limite_aseg_vigencia_tipo == "" || frm_cobertura_limite_aseg_vigencia_tipo == null) {
    r.frm_cobertura_limite_aseg_vigencia_tipo_control_select = "REQUERIDO";
  } else {
    r.frm_cobertura_limite_aseg_vigencia_tipo_control_select = "";
  }

  // 9no Control: deducible mínimo valor negativo o cero
  if (String(r.frm_cobertura_codigo).trim() === '5') {
    r.frm_control_campo_cobertura_deducible_minimo_valor = '';
  } else {
    r.frm_control_campo_cobertura_deducible_minimo_valor =
      frm_cobertura_calculoDeducibleOpcion === "VALOR" &&
      (frm_cobertura_deducible_minimo_valor <= 0 || isNaN(frm_cobertura_deducible_minimo_valor))
        ? "VALOR_INVALIDO" : "";
  }
});

return grd;

const grd = Array.isArray(this.grd_coberturas_seleccionadas)
  ? this.grd_coberturas_seleccionadas
  : [];

const base = Number(this.valor_asegurado_opcion_actual) || 0;

grd.forEach((r) => {
  if (!r) return;

  // Limpiar control por defecto
  r.frm_cobertura_limite_aseg_evento_control = '';

  const eventoValor = Number(r.frm_cobertura_moneda) || 0;

  if (eventoValor > base) {
    r.frm_cobertura_limite_aseg_evento_control = 'EVENTO_SUPERADO';
  }
});

return grd;

function setupGhostScroll(card) {
    // Evitar duplicados si ya existe
    if (card.previousElementSibling && card.previousElementSibling.classList.contains('ghost-scroll-top')) {
      return;
    }

    // Crear el ghost scrollbar
    const ghost = document.createElement('div');
    ghost.className = 'ghost-scroll-top';
    const inner = document.createElement('div');
    ghost.appendChild(inner);

    // Insertarlo justo ANTES del Card-Scrolling
    card.parentNode.insertBefore(ghost, card);

    // Encontrar el contenido real (primer hijo con ancho completo)
    const content = card.firstElementChild;

    // Función para igualar el ancho del ghost al ancho real del contenido
    function syncWidth() {
      const realWidth = content ? content.scrollWidth : card.scrollWidth;
      inner.style.width = realWidth + 'px';
    }

    // Sincronización bidireccional del scroll
    let isSyncing = false;
    ghost.addEventListener('scroll', () => {
      if (isSyncing) { isSyncing = false; return; }
      isSyncing = true;
      card.scrollLeft = ghost.scrollLeft;
    });
    card.addEventListener('scroll', () => {
      if (isSyncing) { isSyncing = false; return; }
      isSyncing = true;
      ghost.scrollLeft = card.scrollLeft;
    });

    // Observar cambios de tamaño (filas que se agregan/quitan, multiselects, etc.)
    if (window.ResizeObserver) {
      const ro = new ResizeObserver(syncWidth);
      ro.observe(card);
      if (content) ro.observe(content);
    }
    window.addEventListener('resize', syncWidth);

    // Ejecutar una vez al inicio
    syncWidth();
    // Re-sincronizar tras el render inicial de Vue
    setTimeout(syncWidth, 100);
    setTimeout(syncWidth, 500);
  }

  function scanAndSetup() {
    document.querySelectorAll('[selector="Card-Scrolling"]').forEach(setupGhostScroll);
  }

  // Ejecutar cuando el DOM esté listo
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', scanAndSetup);
  } else {
    scanAndSetup();
  }

  // Observar DOM por si Vue re-renderiza el Card-Scrolling
  const mo = new MutationObserver(() => scanAndSetup());
  mo.observe(document.body, { childList: true, subtree: true });

