/* ============================================================
   CARD SCROLLING — SCROLL HORIZONTAL (ARRIBA Y ABAJO) + VERTICAL
   ============================================================ */

/* Contenedor real: scroll horizontal abajo + vertical derecha */
[selector="Card-Scrolling"] {
  overflow-x: auto;
  overflow-y: auto;
  max-height: 600px;        /* altura máxima antes de activar scroll vertical */
  width: 100%;
  display: block;
  position: relative;
}

/* Aplica nowrap a TODOS los rows dentro del scroll (encabezado y filas de datos) */
[selector="Card-Scrolling"] .row {
  flex-wrap: nowrap;
  min-width: max-content;
}

/* El container-fluid del grid no debe cortar el ancho */
[selector="Card-Scrolling"] .container-fluid {
  min-width: max-content;
  padding-left: 0;
  padding-right: 0;
}

/* Columnas con ancho mínimo fijo para que no colapsen */
[selector="Card-Scrolling"] .col-sm-1 {
  min-width: 110px;
  max-width: 150px;
  flex-shrink: 0;
}

[selector="Card-Scrolling"] .col-sm-2 {
  /*min-width: 150px;*/
  max-width: 260px;
  flex-shrink: 0;
}

[selector="Card-Scrolling"] .col-sm-3 {
  /*min-width: 200px;*/
  max-width: 110px;
  flex-shrink: 0;
}

[selector="Card-Scrolling"] .col-sm-4 {
  /*min-width: 150px;*/
  max-width: 390px;
  flex-shrink: 0;
}

/* ============================================================
   GHOST SCROLLBAR (ARRIBA) — creado por JS
   ============================================================ */

.ghost-scroll-top {
  overflow-x: auto;
  overflow-y: hidden;
  width: 100%;
  height: 14px;
  margin-bottom: 4px;
}

.ghost-scroll-top > div {
  height: 1px;
}

/* ============================================================
   ESTILO DE SCROLLBARS (WEBKIT: Chrome, Edge, Safari)
   ============================================================ */

[selector="Card-Scrolling"]::-webkit-scrollbar,
.ghost-scroll-top::-webkit-scrollbar {
  height: 12px;   /* scroll horizontal */
  width: 12px;    /* scroll vertical */
}

[selector="Card-Scrolling"]::-webkit-scrollbar-track,
.ghost-scroll-top::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 6px;
}

[selector="Card-Scrolling"]::-webkit-scrollbar-thumb,
.ghost-scroll-top::-webkit-scrollbar-thumb {
  background: #2167AE;
  border-radius: 6px;
}

[selector="Card-Scrolling"]::-webkit-scrollbar-thumb:hover,
.ghost-scroll-top::-webkit-scrollbar-thumb:hover {
  background: #1a5590;
}

/* Esquina donde se cruzan ambos scrollbars */
[selector="Card-Scrolling"]::-webkit-scrollbar-corner {
  background: #f1f1f1;
}

/* Firefox */
[selector="Card-Scrolling"],
.ghost-scroll-top {
  scrollbar-width: thin;
  scrollbar-color: #2167AE #f1f1f1;
}










